L.marker([{station_lat},{station_lon}]).addTo(map).bindPopup('丛台公园监测站');
L.circle([{station_lat},{station_lon}],{{radius:2000,color:'blue',fill:false}}).addTo(map).bindPopup('2公里范围');
var schools={json.dumps(school_geojson, ensure_ascii=False)};
L.geoJSON(schools,{{
  pointToLayer:function(f,latlng){{return L.circleMarker(latlng,{{radius:6,color:'green',fillColor:'green',fillOpacity:0.75}});}},
  onEachFeature:function(f,l){{l.bindPopup(f.properties.name+'<br>'+f.properties.sub_type+'<br>距离监测站：'+f.properties.distance_m+'米');}}
}}).addTo(map);
</script></body></html>"""
